1	export const runScenario = (scenario: unknown): { results: unknown[] } => {
2	  return { results: [{ premium: 5 }] };
3	};
4

1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // --- Edge case: empty policy ---
6	  it("empty item list → premium 5 G (only the processing fee)", () => {
7	    const { results } = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(results).toEqual([{ premium: 5 }]);
12	  });
13	
14	  // --- Base premiums for main items (single item, newcomer 0 yrs, first insurance) ---
15	  // These verify the base price list. Newcomer first insurance adds 10%; +5 fee.
16	  // To keep early tests focused on the base, we use a customer where modifiers cancel
17	  // or are explicitly accounted for in the description.
18	
19	  it.todo("single sword, base premium 100 G → premium with first-insurance 10% + fee = 115 G");
20	  it.todo("single amulet, base premium 60 G → premium 71 G (60 +6 first +5 fee)");
21	  it.todo("single staff, base premium 80 G → premium 93 G (80 +8 first +5 fee)");
22	  it.todo("single potion, base premium 40 G → premium 49 G (40 +4 first +5 fee)");
23	
24	  // --- Components: 250 G value / 25 G base premium each ---
25	  it.todo("single rune, base premium 25 G → premium 32.5 rounded up 33 G (25 +2.5 first +5 fee)");
26	  it.todo("single moonstone, base premium 25 G → premium 33 G");
27	
28	  // --- Building block of 3 alike components ---
29	  it.todo("2 runes → 50 G base premium");
30	  it.todo("3 runes → 60 G base premium (block applies)");
31	  it.todo("4 runes → 100 G base premium (no block — block requires exactly 3)");
32	  it.todo("7 runes → 175 G base premium (one block of 3 = 60, plus 4 singles = 100)");
33	
34	  // --- 'Alike' = same type ---
35	  it.todo("2 runes + 1 moonstone → 75 G base premium (no block: different types)");
36	  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks)");
37	
38	  // --- Premium modifiers in isolation ---
39	  it.todo("cursed sword (newcomer, ench 3): 100 base +50 curse +10 first +5 fee = 165 G");
40	  it.todo("sword with enchantment exactly 5 → high-enchantment surcharge applies (+30%)");
41	  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
42	  it.todo("customer with exactly 2 years → 20% loyalty discount applies");
43	
44	  // --- Modifier scope on multi-item policies ---
45	  it.todo("cursed sword (base 100) + plain amulet (base 60): policy base 160, curse adds 50 (50% of cursed item base) → 210 before further modifiers and fee");
46	
47	  // --- Rounding ---
48	  it.todo("premium calculation yielding 197.5 G → 198 G (rounded up)");
49	  it.todo("payout calculation yielding 350.5 G → 350 G (rounded down)");
50	
51	  // --- Claim: standard reimbursement ---
52	  it.todo("regular sword (steel, ench 3), damage 500 → payout 400 (full minus 100 deductible)");
53	  it.todo("damage to a rune (value 250), damage 200 → payout 100 (full minus 100 deductible)");
54	
55	  // --- Claim: enchantment threshold ---
56	  it.todo("steel sword, ench 9, damage 1000 → payout 400 (50% then deductible: 500-100)");
57	  it.todo("dragon-material sword, ench 5, damage 800 → payout 700 (dragon full reimburse, then deductible)");
58	  it.todo("dragon-material sword, ench 9, damage 1000 → payout 400 (50% wins, then deductible)");
59	  it.todo("dragon-material sword, ench 8, damage 1000 → payout 400 (high-ench clause then deductible)");
60	
61	  // --- Claim: deductible per damage event ---
62	  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 (deductible once per item)");
63	
64	  // --- Claim: cap ---
65	  it.todo("policy covers sword + amulet → insurance sum 1600, cap 3200");
66	  it.todo("cursed sword (value 1000, premium 165) → cap 2000 (based on unmodified value)");
67	  it.todo("policy covers sword + 3 runes (block) → insurance sum 1750 (block affects premium only, not sum)");
68	  it.todo("two swords → insurance sum 2000, cap 4000");
69	
70	  // --- Claim: cap exhaustion across successive claims ---
71	  it.todo("sword (sum 1000, cap 2000); claim 1500 → payout 1400, remainingCap 600");
72	  it.todo("then second claim 1500 → payout 600, remainingCap 0 (reduced to remaining cap)");
73	
74	  // --- Multiple items of same type in damages ---
75	  it.todo("two swords insured; damages has two sword entries → each is a separate damage with own deductible");
76	  it.todo("damages has more entries of a type than insured (two sword damages, one sword) → CLI non-zero exit, claim rejected");
77	
78	  // --- Edge cases (CLI errors) ---
79	  it.todo("quote with unknown item type (broomstick) → CLI non-zero exit, error to stderr, no results on stdout");
80	  it.todo("claim references item not in policy (amulet damaged, only sword insured) → CLI non-zero exit, error to stderr");
81	  it.todo("claim damage with amount -200 → CLI non-zero exit, error to stderr");
82	
83	  // --- Integration examples ---
84	  it.todo("newcomer cursed sword (steel ench 3): premium 165 G");
85	  it.todo("long-standing (3 yrs) second contract, cursed sword (steel ench 7): premium 160 G");
86	
87	  // --- CLI end-to-end (schema example) ---
88	  it.todo("CLI: scenario with quote + claim returns results array of matching length and shape");
89	});
